// GET /api/posts?limit=20&after=<cursor>

/**
 * Encode a compound cursor as an opaque base64 JSON string.
 * Captures the last row's sort key: (created_at, id).
 */
function encodeCursor(row) {
    const payload = {
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    };
    return Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');
}

/**
 * Decode an opaque cursor back into its components.
 * Throws on malformed input so the caller can return a 400.
 */
function decodeCursor(cursor) {
    let decoded;
    try {
        const json = Buffer.from(cursor, 'base64').toString('utf8');
        decoded = JSON.parse(json);
    } catch (err) {
        throw new Error('Malformed cursor');
    }

    if (
        decoded === null ||
        typeof decoded !== 'object' ||
        typeof decoded.id === 'undefined' ||
        typeof decoded.created_at === 'undefined'
    ) {
        throw new Error('Malformed cursor');
    }

    return { created_at: decoded.created_at, id: decoded.id };
}

async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB.
    let limit = parseInt(req.query.limit, 10) || 20;
    limit = Math.max(1, Math.min(limit, 100));

    const after = req.query.after;

    let sql;
    let params;

    if (after) {
        let cursor;
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid cursor' });
        }

        // Compound keyset comparison matching ORDER BY (created_at DESC, id DESC).
        // Row-value tuple: fetch rows strictly "after" the cursor in sort order.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
              AND (created_at, id) < ($1, $2)
            ORDER BY created_at DESC, id DESC
            LIMIT $3
        `;
        params = [cursor.created_at, cursor.id, limit + 1];
    } else {
        // First page: no cursor filter.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        params = [limit + 1];
    }

    const result = await db.query(sql, params);
    const rows = result.rows;

    // N+1 trick: an extra row means there are more pages.
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1])
        : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

## Key implementation notes

- **No OFFSET.** The `(created_at, id) < ($1, $2)` row-value comparison is the cursor filter. PostgreSQL evaluates tuples lexicographically, so this is exactly equivalent to `created_at < $1 OR (created_at = $1 AND id < $2)` but cleaner and index-friendly. It pairs perfectly with `ORDER BY created_at DESC, id DESC` (DESC sort → `<` comparison to walk forward).
- **`id` as a tiebreaker** makes the cursor stable even when multiple posts share the same `created_at` — no rows skipped or duplicated at page boundaries.
- **N+1 trick** replaces the COUNT: fetch `limit + 1`, and if the extra row exists, set `hasMore` and slice it off.
- **Opaque cursor.** Base64-encoded JSON keeps the client from depending on the internal sort key — you can later change the cursor's contents without breaking clients.
- **Graceful failure.** Bad base64, bad JSON, or missing fields all throw and yield a `400`.

## Index recommendation

For this to be fast, back it with a matching composite index:

```sql
CREATE INDEX idx_posts_published_keyset
    ON posts (created_at DESC, id DESC)
    WHERE published = true;
```

## Why cursor-based is superior here

- **Constant performance at depth.** `OFFSET 1000000` forces Postgres to scan and discard a million rows on every request; cost grows linearly with page depth. A keyset cursor seeks directly into the index and reads only `limit + 1` rows — page 1 and page 100,000 cost the same.
- **No skipped/duplicated rows.** With offset pagination, if a post is inserted or deleted while a user pages through, the offset window shifts and rows get repeated or missed. The cursor anchors to a stable `(created_at, id)` position, so concurrent writes don't corrupt the result set.
- **Cheaper.** Dropping the `COUNT(*)` removes a full-table aggregate that gets very expensive as the table grows — and an exact total count is rarely needed for infinite-scroll/feed UIs.

**Trade-off:** you lose random access to arbitrary page numbers (no "jump to page 50"), which is why cursor pagination fits feeds/timelines rather than numbered-page UIs.

